import sqlite3

def get_order_info(user_id, order_id):
    conn = sqlite3.connect('database.db')
    cursor = conn.cursor()
    
    # Secure query with user_id and order_id validation
    cursor.execute("""
        SELECT order_id, user_id, product_name, quantity, price, status, created_at 
        FROM orders 
        WHERE order_id = ? AND user_id = ?
    """, (order_id, user_id))
    
    row = cursor.fetchone()
    conn.close()
    
    if row:
        return {
            'order_id': row[0],
            'user_id': row[1],
            'product_name': row[2],
            'quantity': row[3],
            'price': row[4],
            'status': row[5],
            'created_at': row[6]
        }
    return None